CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_adv` ( `id` int(11) NOT NULL AUTO_INCREMENT, `advname` varchar(50) DEFAULT '', `link` varchar(255) DEFAULT '', `thumb` varchar(255) DEFAULT '', `displayorder` int(11) DEFAULT '0', `enabled` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_enabled` (`enabled`), KEY `idx_displayorder` (`displayorder`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `logno` varchar(50) DEFAULT NULL, `code` varchar(255) DEFAULT NULL, `uniacid` int(11) NOT NULL DEFAULT '0', `pluginid` int(11) NOT NULL DEFAULT '0', `identity` varchar(50) DEFAULT NULL, `type` varchar(255) DEFAULT NULL, `month` int(10) NOT NULL DEFAULT '0', `permendtime` int(10) NOT NULL DEFAULT '0', `permlasttime` int(10) NOT NULL DEFAULT '0', `isperm` tinyint(3) NOT NULL DEFAULT '0', `createtime` int(10) NOT NULL DEFAULT '0', `deleted` tinyint(3) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_order` ( `id` int(11) NOT NULL AUTO_INCREMENT, `logno` varchar(50) DEFAULT NULL, `code` varchar(255) DEFAULT NULL, `uniacid` int(11) NOT NULL DEFAULT '0', `username` varchar(255) DEFAULT NULL, `pluginid` varchar(255) DEFAULT NULL, `price` decimal(10,2) NOT NULL DEFAULT '0.00', `month` int(11) NOT NULL DEFAULT '0', `createtime` int(10) NOT NULL DEFAULT '0', `paystatus` tinyint(3) NOT NULL DEFAULT '0', `paytime` int(10) NOT NULL DEFAULT '0', `paytype` tinyint(3) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_package` ( `id` int(11) NOT NULL AUTO_INCREMENT, `pluginid` varchar(255) NOT NULL DEFAULT '', `text` varchar(255) DEFAULT NULL, `thumb` varchar(1000) DEFAULT NULL, `data` text NOT NULL, `state` tinyint(3) NOT NULL DEFAULT '0', `rec` tinyint(3) NOT NULL DEFAULT '0', `desc` varchar(255) DEFAULT NULL, `content` text NOT NULL, `displayorder` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_plugin` ( `id` int(11) NOT NULL AUTO_INCREMENT, `pluginid` int(11) NOT NULL DEFAULT '0', `thumb` varchar(1000) NOT NULL, `data` text, `state` tinyint(3) NOT NULL DEFAULT '0', `content` text NOT NULL, `sales` int(11) NOT NULL DEFAULT '0', `createtime` int(10) NOT NULL DEFAULT '0', `displayorder` int(11) NOT NULL DEFAULT '0', `plugintype` tinyint(3) NOT NULL DEFAULT '0', `name` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_plugingrant_setting` ( `id` int(11) NOT NULL AUTO_INCREMENT, `com` varchar(1000) NOT NULL DEFAULT '', `adv` varchar(1000) NOT NULL, `plugin` varchar(1000) NOT NULL, `customer` varchar(50) NOT NULL DEFAULT '0', `contact` text NOT NULL, `servertime` varchar(255) DEFAULT NULL, `weixin` tinyint(3) NOT NULL DEFAULT '0', `appid` varchar(255) DEFAULT NULL, `mchid` varchar(255) DEFAULT NULL, `apikey` varchar(255) DEFAULT NULL, `alipay` tinyint(3) NOT NULL, `account` varchar(255) DEFAULT NULL, `partner` varchar(255) DEFAULT NULL, `secret` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_setting` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(10) DEFAULT NULL, `background` varchar(10) DEFAULT '', `casebanner` varchar(255) DEFAULT '', `contact` text, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
