CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `title` varchar(255) NOT NULL DEFAULT '', `type` int(11) NOT NULL, `starttime` int(11) NOT NULL, `endtime` int(11) NOT NULL, `dotime` int(11) NOT NULL DEFAULT '0', `donetime` int(11) NOT NULL DEFAULT '0', `timelimit` float(11,1) NOT NULL, `keyword` varchar(255) NOT NULL DEFAULT '', `status` tinyint(1) NOT NULL DEFAULT '0', `explain` text, `require_data` text NOT NULL, `reward_data` text NOT NULL, `period` int(11) NOT NULL DEFAULT '0', `repeat` int(11) NOT NULL DEFAULT '0', `maxtimes` int(11) NOT NULL DEFAULT '0', `everyhours` float(11,1) NOT NULL DEFAULT '0.0', `logo` varchar(255) NOT NULL DEFAULT '', PRIMARY KEY (`id`), KEY `uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_adv` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `advname` varchar(50) DEFAULT '', `link` varchar(255) DEFAULT '', `thumb` varchar(255) DEFAULT '', `displayorder` int(11) DEFAULT '0', `enabled` int(11) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
