CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_extension` ( `id` int(11) NOT NULL AUTO_INCREMENT, `taskname` varchar(255) NOT NULL DEFAULT '', `taskclass` varchar(25) NOT NULL DEFAULT '', `status` tinyint(1) NOT NULL DEFAULT '0', `classify` varchar(255) NOT NULL DEFAULT '', `classify_name` varchar(255) NOT NULL DEFAULT '', `verb` varchar(255) NOT NULL DEFAULT '', `unit` varchar(255) NOT NULL DEFAULT '', PRIMARY KEY (`id`) ) ENGINE=MyISAM AUTO_INCREMENT=14 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_extension_join` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `title` varchar(255) NOT NULL DEFAULT '', `uid` int(11) NOT NULL, `taskid` int(11) NOT NULL, `openid` varchar(255) NOT NULL, `require_data` text NOT NULL, `progress_data` text NOT NULL, `reward_data` text NOT NULL, `completetime` int(11) NOT NULL DEFAULT '0', `pickuptime` int(11) NOT NULL, `endtime` int(11) NOT NULL, `dotime` int(11) NOT NULL DEFAULT '0', `rewarded` text NOT NULL, `logo` varchar(255) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_join` ( `join_id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `join_user` varchar(100) NOT NULL DEFAULT '', `task_id` int(11) NOT NULL DEFAULT '0', `task_type` tinyint(1) NOT NULL DEFAULT '0', `needcount` int(11) NOT NULL DEFAULT '0', `completecount` int(11) NOT NULL DEFAULT '0', `reward_data` text, `is_reward` tinyint(1) NOT NULL DEFAULT '0', `failtime` int(11) NOT NULL DEFAULT '0', `addtime` int(11) DEFAULT '0', PRIMARY KEY (`join_id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
