CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_list` ( `status` tinyint(1) NOT NULL DEFAULT '0', `displayorder` int(11) NOT NULL DEFAULT '0', `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `title` char(50) NOT NULL DEFAULT '', `image` varchar(255) NOT NULL DEFAULT '', `type` varchar(50) NOT NULL DEFAULT '', `starttime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `endtime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `demand` int(11) NOT NULL DEFAULT '0', `requiregoods` text NOT NULL, `picktype` tinyint(1) NOT NULL DEFAULT '0', `stop_type` tinyint(1) NOT NULL DEFAULT '0', `stop_limit` int(11) NOT NULL DEFAULT '0', `stop_time` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `stop_cycle` tinyint(1) NOT NULL DEFAULT '0', `repeat_type` tinyint(1) NOT NULL DEFAULT '0', `repeat_interval` int(11) NOT NULL DEFAULT '0', `repeat_cycle` tinyint(1) NOT NULL DEFAULT '0', `reward` text NOT NULL, `followreward` text NOT NULL, `goods_limit` int(11) NOT NULL DEFAULT '0', `notice` text NOT NULL, `design_data` text NOT NULL, `design_bg` varchar(255) NOT NULL DEFAULT '', `native_data` text NOT NULL, `native_data2` text, `native_data3` text, `reward2` text, `reward3` text, `level2` int(11) NOT NULL DEFAULT '0', `level3` int(11) NOT NULL DEFAULT '0', `member_group` text, `auto_pick` tinyint(1) NOT NULL DEFAULT '0', `keyword_pick` varchar(20) NOT NULL DEFAULT '', `verb` varchar(255) DEFAULT '', `unit` varchar(255) DEFAULT '', `member_level` int(11) NOT NULL DEFAULT '0', `poster_version` varchar(255) NOT NULL DEFAULT '', `we7_rule_keyword_id` int(10) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_passive` (`picktype`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `openid` varchar(100) NOT NULL DEFAULT '', `from_openid` varchar(100) NOT NULL DEFAULT '', `join_id` int(11) NOT NULL DEFAULT '0', `taskid` int(11) DEFAULT '0', `task_type` tinyint(1) NOT NULL DEFAULT '0', `subdata` text, `recdata` text, `createtime` int(11) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_poster` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `days` int(11) NOT NULL DEFAULT '0', `title` varchar(255) DEFAULT NULL, `bg` varchar(255) DEFAULT '', `data` text, `keyword` varchar(255) DEFAULT NULL, `resptype` tinyint(1) NOT NULL DEFAULT '0', `resptext` text, `resptitle` varchar(255) DEFAULT NULL, `respthumb` varchar(255) DEFAULT NULL, `respdesc` varchar(255) DEFAULT NULL, `respurl` varchar(255) DEFAULT NULL, `createtime` int(11) DEFAULT NULL, `waittext` varchar(255) DEFAULT NULL, `oktext` varchar(255) DEFAULT NULL, `scantext` varchar(255) DEFAULT NULL, `beagent` tinyint(1) NOT NULL DEFAULT '0', `bedown` tinyint(1) NOT NULL DEFAULT '0', `timestart` int(11) DEFAULT NULL, `timeend` int(11) DEFAULT NULL, `is_repeat` tinyint(1) DEFAULT '0', `getposter` varchar(255) DEFAULT NULL, `status` tinyint(1) DEFAULT NULL, `starttext` varchar(255) DEFAULT NULL, `endtext` varchar(255) DEFAULT NULL, `reward_data` text, `needcount` int(11) NOT NULL DEFAULT '0', `is_delete` tinyint(1) NOT NULL DEFAULT '0', `poster_type` tinyint(1) DEFAULT '1', `reward_days` int(11) DEFAULT '0', `titleicon` text, `poster_banner` text, `is_goods` tinyint(1) DEFAULT '0', `autoposter` tinyint(1) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_poster_qr` ( `id` int(11) NOT NULL AUTO_INCREMENT, `acid` int(11) NOT NULL DEFAULT '0', `openid` varchar(100) NOT NULL, `posterid` int(11) NOT NULL DEFAULT '0', `type` tinyint(1) NOT NULL DEFAULT '0', `sceneid` int(11) NOT NULL DEFAULT '0', `mediaid` varchar(255) DEFAULT NULL, `ticket` varchar(255) NOT NULL, `url` varchar(255) NOT NULL, `createtime` int(11) DEFAULT NULL, `qrimg` varchar(1000) DEFAULT NULL, `expire` int(11) DEFAULT NULL, `endtime` int(11) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
