CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_record` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `taskid` int(11) NOT NULL DEFAULT '0', `tasktitle` varchar(255) NOT NULL, `taskimage` varchar(255) NOT NULL DEFAULT '', `tasktype` varchar(50) NOT NULL DEFAULT '', `task_progress` int(11) NOT NULL DEFAULT '0', `task_demand` int(11) NOT NULL DEFAULT '0', `openid` char(50) NOT NULL DEFAULT '', `nickname` varchar(255) NOT NULL DEFAULT '', `picktime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `stoptime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `finishtime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `reward_data` text NOT NULL, `followreward_data` text NOT NULL, `design_data` text NOT NULL, `design_bg` varchar(255) NOT NULL DEFAULT '', `require_goods` varchar(255) NOT NULL DEFAULT '', `level1` int(11) NOT NULL DEFAULT '0', `reward_data1` text NOT NULL, `level2` int(11) NOT NULL DEFAULT '0', `reward_data2` text NOT NULL, `member_group` text, `auto_pick` tinyint(1) NOT NULL, PRIMARY KEY (`id`), KEY `uniacid` (`uniacid`), KEY `taskid` (`taskid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_reward` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `taskid` int(11) NOT NULL DEFAULT '0', `tasktitle` char(50) NOT NULL DEFAULT '', `tasktype` varchar(50) NOT NULL DEFAULT '', `taskowner` char(50) NOT NULL DEFAULT '', `ownernickname` char(50) NOT NULL DEFAULT '', `recordid` int(11) NOT NULL DEFAULT '0', `nickname` char(50) NOT NULL DEFAULT '', `headimg` varchar(255) NOT NULL DEFAULT '', `openid` char(50) NOT NULL DEFAULT '', `reward_type` char(10) NOT NULL DEFAULT '', `reward_title` char(50) NOT NULL DEFAULT '', `reward_data` decimal(10,2) NOT NULL DEFAULT '0.00', `get` tinyint(1) NOT NULL DEFAULT '0', `sent` tinyint(1) NOT NULL DEFAULT '0', `gettime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `senttime` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00', `isjoiner` tinyint(1) NOT NULL DEFAULT '0', `price` decimal(10,2) NOT NULL DEFAULT '0.00', `level` tinyint(1) NOT NULL DEFAULT '0', `read` tinyint(1) NOT NULL, PRIMARY KEY (`id`), KEY `uniacid` (`uniacid`), KEY `recordid` (`recordid`), KEY `taskid` (`taskid`), KEY `get` (`get`), KEY `openid` (`openid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_set` ( `uniacid` int(11) NOT NULL DEFAULT '0', `entrance` tinyint(1) NOT NULL DEFAULT '0', `keyword` varchar(10) NOT NULL DEFAULT '', `cover_title` varchar(20) NOT NULL DEFAULT '', `cover_img` varchar(255) NOT NULL DEFAULT '', `cover_desc` varchar(255) NOT NULL DEFAULT '', `msg_pick` text NOT NULL, `msg_progress` text NOT NULL, `msg_finish` text NOT NULL, `msg_follow` text NOT NULL, `isnew` tinyint(1) NOT NULL DEFAULT '0', `bg_img` varchar(255) NOT NULL DEFAULT '../addons/ewei_shopv2/plugin/task/static/images/sky.png', `top_notice` tinyint(1) DEFAULT NULL, PRIMARY KEY (`uniacid`), KEY `uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_task_type` ( `id` int(11) NOT NULL, `type_key` char(20) NOT NULL DEFAULT '', `type_name` char(10) NOT NULL DEFAULT '', `description` char(30) NOT NULL DEFAULT '', `verb` char(11) NOT NULL DEFAULT '', `numeric` tinyint(1) NOT NULL DEFAULT '0', `unit` char(10) NOT NULL DEFAULT '', `goods` tinyint(1) NOT NULL DEFAULT '0', `theme` char(10) NOT NULL DEFAULT '', `once` tinyint(1) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_touch_loop_list` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `goods_id` int(11) NOT NULL DEFAULT '0', `content` text NOT NULL, `thumbs` text, `sort` int(11) DEFAULT '0', `credted_at` int(11) DEFAULT '0', `status` tinyint(3) DEFAULT '1', `isrecommand` tinyint(3) DEFAULT '0', PRIMARY KEY (`id`), KEY `index_uniacid` (`uniacid`), KEY `index_status` (`status`), KEY `index_goods_id` (`goods_id`), KEY `index_isrecommand` (`isrecommand`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_transfer_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `from_user` varchar(255) NOT NULL DEFAULT '', `to_user` varchar(255) DEFAULT '', `type` tinyint(4) DEFAULT '0', `credit_type` varchar(10) DEFAULT '', `service_recharge` decimal(10,2) DEFAULT '0.00', `create_time` int(11) DEFAULT '0', `from_surplus` decimal(10,2) DEFAULT '0.00', `to_surplus` decimal(10,2) DEFAULT '0.00', `credit` decimal(10,2) DEFAULT '0.00', `final_price` decimal(10,2) NOT NULL DEFAULT '0.00', `service_recharge_scale` varchar(20) NOT NULL DEFAULT '', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_universalform_category` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `name` varchar(50) DEFAULT NULL, `merch` int(11) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_universalform_data` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `typeid` int(11) NOT NULL DEFAULT '0', `cid` int(11) DEFAULT '0', `fields` text NOT NULL, `universalformfields` text, `openid` varchar(255) NOT NULL DEFAULT '', `type` tinyint(2) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_typeid` (`typeid`), KEY `idx_cid` (`cid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_universalform_temp` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `typeid` int(11) DEFAULT '0', `cid` int(11) NOT NULL DEFAULT '0', `universalformfields` text, `fields` text NOT NULL, `openid` varchar(255) NOT NULL DEFAULT '', `type` tinyint(1) DEFAULT '0', `universalformid` int(11) DEFAULT '0', `universalformdata` text, `carrier_realname` varchar(255) DEFAULT '', `carrier_mobile` varchar(255) DEFAULT '', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_cid` (`cid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
